local a=require"cc.expect"local b=require"ecnet2.constants"local function c(d)a.expect(1,d,"string")assert(peripheral.getType(d)=="modem","no such modem: "..d)peripheral.call(d,"open",b.CHANNEL)end;local function e(d)a.expect(1,d,"string","nil")if d then assert(peripheral.getType(d)=="modem","no such modem: "..d)return peripheral.call(d,"close",b.CHANNEL)else peripheral.find("modem",e)end end;local function f(d)a.expect(1,d,"string","nil")if d then if peripheral.getType(d)~="modem"then return false end;return peripheral.call(d,"isOpen",b.CHANNEL)else return not not peripheral.find("modem",f)end end;local function g(h,i)return pcall(peripheral.call,h,"transmit",b.CHANNEL,b.CHANNEL,i)end;return{open=c,close=e,isOpen=f,transmit=g}
